    div.archive-title > div.bread_nav,
    div#show_cg_html > p,
    span.sun_input_group_btn,
    #ReplacePage_select_02,
    #but_Next_02,
    #but_Prev_02,
    #cg_width_select_02,
    .plyr__control[data-plyr="rewind"],
    .plyr__control[data-plyr="fast-forward"],
    .plyr__volume,
    .plyr__menu,
    .plyr__control--overlaid,
    div.content:not(:has(> div.archive-title > a[href="https://18av.mm-cg.com/zh/uncensored_random/all/index.html"])):not(:has(> div.archive-title > a[href="https://18av.mm-cg.com/zh/animation_random/all/index.html"])):not(:has(> div.archive-title > div.bread_nav)),
    ul.sun_input_group__child > li:not(:has(> a[onclick="changetextval(\"無碼AV\",\"uncensoredonly\");"])):not(:has(> a[onclick="changetextval(\"H動畫\",\"animationonly\");"])) {
        display: none !important;
    }

    /* =========================================================
       2. 基礎設定與容器排版
       ========================================================= */
    body {
        margin: 0 !important;
        font-family: var(--stylus-font-sans-serif) !important;
    }

    body:has(> .plyr_width) {
        display: flex !important;
        flex-direction: column !important;
        justify-content: center !important;
        height: 100vh !important;
        margin: 0 !important;
    }

    /* =========================================================
       3. 標題與內容區塊
       ========================================================= */
    div.content {
        padding: 1rem !important;
    }

    div.container > div.contents > div.content {
        font-size: 0 !important;
    }

    div.container > div.contents > div.content:has(span.content_18h_wpcg) {
        padding: 0 !important;
    }

    div.archive-title > a > h1 {
        font-size: 1rem !important;
    }

    div.main > div.container > div.contents > div.content > div.archive-title > h1 {
        padding: 0 1rem !important;
        font-size: 1rem !important;
        font-weight: normal !important;
    }

    div.main > div.container_small > div.video-wrap > div.left > div.archive-title > h1 {
        font-size: 1rem !important;
        font-weight: normal !important;
    }

    /* =========================================================
       4. 列表與縮圖 (Posts & Thumbnails)
       ========================================================= */
    div.posts {
        display: flex !important;
        flex-direction: column !important;
    }

    div.posts > div.post {
        float: none !important;
        width: 100% !important;
        margin: 0 !important;
    }

    div.content:not(.hcomicsversion) div.con {
        height: 100px !important;
    }

    div.content:not(.hcomicsversion) div.con > h3 > a {
        user-select: text !important;
    }

    div.content:not(.hcomicsversion) > div.posts > div.post .thumb {
        height: auto !important;
        aspect-ratio: 16 / 9 !important;
        object-fit: cover !important;
    }

    /* 漫畫模式特例 (.hcomicsversion) */
    div.hcomicsversion > div.posts {
        flex-direction: row !important;
        flex-wrap: wrap !important;
        justify-content: space-between !important;
    }

    div.hcomicsversion > div.posts > div.post {
        position: relative !important;
        flex-shrink: 0 !important;
        width: calc(50% - 0.5rem) !important;
    }

    div.content.hcomicsversion > div.posts > div.post .thumb {
        height: 16rem !important;
        object-fit: cover !important;
    }

    /* =========================================================
       5. 按鈕與選單元件 (Forms & Buttons)
       ========================================================= */
    center form #MainMenu_but {
        display: flex !important;
        flex-direction: column-reverse !important;
        text-align: center !important;
    }

    /* 提取按鈕與下拉選單的共用重置屬性 */
    center form .but_enlarge,
    center form select.sel_enlarge_page {
        appearance: none !important;
        -moz-appearance: none !important;
        -webkit-appearance: none !important; /* 確保行動端樣式重置 */
        border: none !important;
        display: block !important;
        width: auto !important;
        height: auto !important;
        margin: 0.5rem 1rem !important;
        font-size: 1rem !important;
    }

    center form .but_enlarge {
        box-sizing: border-box !important;
        position: relative !important;
        padding: 8rem !important;
    }

    center form .but_enlarge#but_Prev {
        padding: 1rem !important;
    }

    center form select.sel_enlarge_page {
        padding: 0.8rem 1rem !important;
        text-align: center !important;
    }

    /* =========================================================
       6. 影片播放區塊與下載連結
       ========================================================= */
    div.main > div.container_small > div.video-wrap > div.left > div#dz_video {
        height: auto !important;
    }

    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row {
        height: auto !important;
        margin: 0 !important;
        padding: 0 !important;
    }

    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row > span.dwlink {
        position: relative !important;
        bottom: unset !important;
    }

    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row > span.dwlink > a {
        display: block !important;
        padding: 16rem 8rem !important;
        border: none !important;
        font-weight: normal !important;
        font-size: 0 !important;
        text-align: center !important;
        text-decoration: none !important;
    }

    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row > span.dwlink > a::before {
        content: "播放影片" !important;
        font-size: 1rem !important;
    }

    /* =========================================================
       7. 頂部選單與搜尋列 (Search & Nav)
       ========================================================= */
    div.sun_search_form_container {
        float: none !important;
    }

    span.animenu__top_content {
        position: relative !important;
    }

    span.animenu__top_r {
        float: none !important;
        height: auto !important;
        padding: 1rem 8px !important;
    }

    span.sun-search_input_group {
        position: relative !important;
        display: flex !important;
        flex-wrap: nowrap !important;
        width: 100% !important;
        max-width: unset !important;
        margin: 0 !important;
        padding: 0 !important;
        border: none !important;
    }

    span.sun-search_input_group > input.sun-search_input_text {
        float: none !important;
        max-width: unset !important;
        height: unset !important;
        margin-bottom: 0 !important;
        padding: 0.8rem 1rem !important;
        border-right: 2px solid var(--stylus-bg-dark) !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown {
        width: 25% !important;
        padding: 0.8rem 1rem !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown::before {
        border: none !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown > div.sun_input_group_txt {
        margin: 0 !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown > ul.sun_input_group__child {
        left: 0 !important;
        border: none !important;
        background-color: transparent !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown > ul.sun_input_group__child > li > a {
        padding: 0.8rem 1rem !important;
        line-height: unset !important;
    }

    span.sun-search_input_group > div.sun_input_group_dropdown > ul.sun_input_group__child > li > a::after {
        border: none !important;
    }

    span.top_list_block_hide {
        top: 0 !important;
    }

    /* =========================================================
       8. 分頁與其他 UI 細節 (Pagination & Misc)
       ========================================================= */
    div.pagination-row > ul > li {
        border: 1px solid var(--stylus-bg-input-dark) !important;
    }

    div.pagination-row > ul > li > i.fa {
        font-style: normal !important;
    }

    /* =========================================================
       9. Plyr 播放器控制與縮圖
       ========================================================= */
    .plyr__controls {
        background: rgba(0, 0, 0, 0.5) !important;
        padding-top: var(--plyr-control-spacing, 10px) !important;
        transition: unset !important;
    }

    video.thumb {
        pointer-events: none;
    }

    /* =========================================================
       10. 佈景主題：深色模式變數對應 (Theme Colors)
       ========================================================= */
    body,
    center form .but_enlarge,
    div.container > div.contents > div.content,
    div.main > div.container_small > div.video-wrap > div.left,
    span.animenu__top_r {
        background-color: var(--stylus-bg-dark) !important;
    }

    center form select.sel_enlarge_page,
    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row > span.dwlink > a,
    div.pagination-row > ul > li.current > a,
    div.pagination-row > ul > li:hover > a,
    span.sun-search_input_group > div.sun_input_group_dropdown,
    span.sun-search_input_group > div.sun_input_group_dropdown > ul.sun_input_group__child > li > a,
    span.sun-search_input_group > input.sun-search_input_text {
        background-color: var(--stylus-bg-input-dark) !important;
    }

    center form select.sel_enlarge_page,
    div.archive-title > a,
    div.con > h3 > a,
    div.main > div.container > div.contents > div.content > div.archive-title > h1,
    div.main > div.container_small > div.video-wrap > div.left > center > div#mvspan_2 > div.video-row > span.dwlink > a,
    div.main > div.container_small > div.video-wrap > div.left > div.archive-title > h1,
    div.pagination-row > ul > li > a,
    div.pagination-row > ul > li > i.fa > a,
    div.pagination-row > ul > li.current > a,
    span.sun-search_input_group > div.sun_input_group_dropdown,
    span.sun-search_input_group > div.sun_input_group_dropdown > div.sun_input_group_txt > a.sun_input_group_txt,
    span.sun-search_input_group > div.sun_input_group_dropdown > ul.sun_input_group__child > li > a,
    span.sun-search_input_group > input.sun-search_input_text {
        color: var(--stylus-text-dark) !important;
    }
}

/* =========================================================
   11. 行動裝置直立狀態微調
   ========================================================= */
@media (pointer: coarse) and (orientation: portrait) and (max-width: 767px) {
    .plyr__controls {
        bottom: calc(50svh - 126px) !important;
    }
    .plyr__controls .plyr__progress__container {
        position: relative !important;
        bottom: auto !important;
    }
    .plyr__controls .plyr__controls__item:nth-child(2) {
        width: auto !important;
    }
}
